from functools import lru_cache

def can_win(s: str) -> bool:
    @lru_cache(maxsize=None)
    def helper(state: str) -> bool:
        arr = list(state)
        for i in range(len(arr) - 1):
            if arr[i] == '+' and arr[i + 1] == '+':
                arr[i] = arr[i + 1] = '-'
                opponent_wins = helper(''.join(arr))
                arr[i] = arr[i + 1] = '+'
                if not opponent_wins:
                    return True
        return False
    return helper(s)
